        "path": "cronos-the-new-dawn-trainer/TrainerCore.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\nusing System.Threading.Tasks;\n\nnamespace CronosNewDawnTrainer\n{\n    /// <summary>\n    /// Core trainer class that handles memory reading/writing for the game process.\n    /// Provides methods to modify player stats, resources, and game state.\n    /// </summary>\n    public class TrainerCore : IDisposable\n    {\n        private Process _gameProcess;\n        private IntPtr _processHandle;\n        private bool _isAttached;\n\n        // Memory offsets for various game values (example addresses)\n        private const long HealthOffset = 0x00A3F1C0;\n        private const long ManaOffset = 0x00A3F1C8;\n        private const long GoldOffset = 0x00B2A430;\n        private const long ExperienceOffset = 0x00B2A438;\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint ProcessAllAccess = 0x1F0FFF;\n\n        /// <summary>\n        /// Attaches to the game process by name.\n        /// </summary>\n        /// <param name=\"processName\">Name of the game process (e.g., \"CronosNewDawn\")</param>\n        /// <returns>True if attachment successful</returns>\n        public bool AttachToProcess(string processName = \"CronosNewDawn\")\n        {\n            try\n            {\n                Process[] processes = Process.GetProcessesByName(processName);\n                if (processes.Length == 0)\n                {\n                    Console.WriteLine($\"Process '{processName}' not found.\");\n                    return false;\n                }\n\n                _gameProcess = processes[0];\n                _processHandle = OpenProcess(ProcessAllAccess, false, _gameProcess.Id);\n\n                if (_processHandle == IntPtr.Zero)\n                {\n                    Console.WriteLine(\"Failed to open process. Try running as administrator.\");\n                    return false;\n                }\n\n                _isAttached = true;\n                Console.WriteLine($\"Attached to {processName} (PID: {_gameProcess.Id})\");\n                return true;\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Attachment error: {ex.Message}\");\n                return false;\n            }\n        }\n\n        /// <summary>\n        /// Reads an integer value from a specified memory address.\n        /// </summary>\n        private int ReadInt(IntPtr address)\n        {\n            if (!_isAttached) return 0;\n\n            byte[] buffer = new byte[sizeof(int)];\n            if (ReadProcessMemory(_processHandle, address, buffer, buffer.Length, out _))\n            {\n                return BitConverter.ToInt32(buffer, 0);\n            }\n            return 0;\n        }\n\n        /// <summary>\n        /// Writes an integer value to a specified memory address.\n        /// </summary>\n        private bool WriteInt(IntPtr address, int value)\n        {\n            if (!_isAttached) return false;\n\n            byte[] buffer = BitConverter.GetBytes(value);\n            return WriteProcessMemory(_processHandle, address, buffer, buffer.Length, out _);\n        }\n\n        /// <summary>\n        /// Gets the current health value.\n        /// </summary>\n        public int GetHealth()\n        {\n            return ReadInt((IntPtr)HealthOffset);\n        }\n\n        /// <summary>\n        /// Sets the health to a specified value.\n        /// </summary>\n        public bool SetHealth(int value)\n        {\n            return WriteInt((IntPtr)HealthOffset, Math.Max(0, value));\n        }\n\n        /// <summary>\n        /// Gets the current mana value.\n        /// </summary>\n        public int GetMana()\n        {\n            return ReadInt((IntPtr)ManaOffset);\n        }\n\n        /// <summary>\n        /// Sets the mana to a specified value.\n        /// </summary>\n        public bool SetMana(int value)\n        {\n            return WriteInt((IntPtr)ManaOffset, Math.Max(0, value));\n        }\n\n        /// <summary>\n        /// Gets the current gold amount.\n        /// </summary>\n        public int GetGold()\n        {\n            return ReadInt((IntPtr)GoldOffset);\n        }\n\n        /// <summary>\n        /// Sets the gold amount.\n        /// </summary>\n        public bool SetGold(int value)\n        {\n            return WriteInt((IntPtr)GoldOffset, Math.Max(0, value));\n        }\n\n        /// <summary>\n        /// Gets the current experience points.\n        /// </summary>\n        public int GetExperience()\n        {\n            return ReadInt((IntPtr)ExperienceOffset);\n        }\n\n        /// <summary>\n        /// Sets the experience points.\n        /// </summary>\n        public bool SetExperience(int value)\n        {\n            return WriteInt((IntPtr)ExperienceOffset, Math.Max(0, value));\n        }\n\n        /// <summary>\n        /// Infinitely sets health to maximum (god mode) by repeatedly writing 9999.\n        /// Runs until cancellation is requested.\n        /// </summary>\n        public async Task EnableGodMode(CancellationToken cancellationToken)\n        {\n            Console.WriteLine(\"God mode enabled. Press Ctrl+C to stop.\");\n            while (!cancellationToken.IsCancellationRequested)\n            {\n                SetHealth(9999);\n                await Task.Delay(100, cancellationToken);\n            }\n        }\n\n        /// <summary>\n        /// Adds a specified amount of gold.\n        /// </summary>\n        public bool AddGold(int amount)\n        {\n            int current = GetGold();\n            return SetGold(current + amount);\n        }\n\n        /// <summary>\n        /// Disposes the process handle and cleans up.\n        /// </summary>\n        public void Dispose()\n        {\n            if (_processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                _processHandle = IntPtr.Zero;\n            }\n            _isAttached = false;\n            Console.WriteLine(\"Trainer detached.\");\n        }\n    }\n}\n"
    },
