        "path": "cronos-the-new-dawn-trainer/TrainerUI.cs",
        "content": "using System;\nusing System.Threading;\nusing System.Threading.Tasks;\n\nnamespace CronosNewDawnTrainer\n{\n    /// <summary>\n    /// Console-based user interface for the Cronos: The New Dawn Trainer.\n    /// Provides interactive menu for controlling trainer features.\n    /// </summary>\n    public class TrainerUI\n    {\n        private readonly TrainerCore _trainer;\n        private CancellationTokenSource _cts;\n\n        public TrainerUI(TrainerCore trainer)\n        {\n            _trainer = trainer;\n            _cts = new CancellationTokenSource();\n        }\n\n        /// <summary>\n        /// Starts the interactive console UI loop.\n        /// </summary>\n        public async Task RunAsync()\n        {\n            Console.Clear();\n            Console.WriteLine(\"=== Cronos: The New Dawn Trainer ===\");\n            Console.WriteLine(\"Version 1.0.0\");\n            Console.WriteLine();\n\n            if (!_trainer.AttachToProcess())\n            {\n                Console.WriteLine(\"Make sure the game is running and try again.\");\n                Console.WriteLine(\"Press any key to exit...\");\n                Console.ReadKey();\n                return;\n            }\n\n            bool exit = false;\n            while (!exit)\n            {\n                DisplayMenu();\n                string input = Console.ReadLine()?.Trim().ToLower();\n\n                switch (input)\n                {\n                    case \"1\":\n                        await ToggleGodMode();\n                        break;\n                    case \"2\":\n                        SetHealthManually();\n                        break;\n                    case \"3\":\n                        SetManaManually();\n                        break;\n                    case \"4\":\n                        AddGoldPrompt();\n                        break;\n                    case \"5\":\n                        SetExperienceManually();\n                        break;\n                    case \"6\":\n                        ShowCurrentStats();\n                        break;\n                    case \"7\":\n                        exit = true;\n                        _cts.Cancel();\n                        Console.WriteLine(\"Exiting trainer...\");\n                        break;\n                    default:\n                        Console.WriteLine(\"Invalid option. Please try again.\");\n                        break;\n                }\n            }\n        }\n\n        private void DisplayMenu()\n        {\n            Console.WriteLine();\n            Console.WriteLine(\"--- Main Menu ---\");\n            Console.WriteLine(\"1. Toggle God Mode\");\n            Console.WriteLine(\"2. Set Health\");\n            Console.WriteLine(\"3. Set Mana\");\n            Console.WriteLine(\"4. Add Gold\");\n            Console.WriteLine(\"5. Set Experience\");\n            Console.WriteLine(\"6. Show Current Stats\");\n            Console.WriteLine(\"7. Exit\");\n            Console.Write(\"Select an option: \");\n        }\n\n        private async Task ToggleGodMode()\n        {\n            Console.WriteLine(\"Starting God Mode (health set to 9999 repeatedly)...\");\n            _cts = new CancellationTokenSource();\n            try\n            {\n                await _trainer.EnableGodMode(_cts.Token);\n            }\n            catch (OperationCanceledException)\n            {\n                Console.WriteLine(\"God mode stopped.\");\n            }\n        }\n\n        private void SetHealthManually()\n        {\n            Console.Write(\"Enter new health value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                if (_trainer.SetHealth(value))\n                    Console.WriteLine($\"Health set to {value}.\");\n                else\n                    Console.WriteLine(\"Failed to set health.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void SetManaManually()\n        {\n            Console.Write(\"Enter new mana value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                if (_trainer.SetMana(value))\n                    Console.WriteLine($\"Mana set to {value}.\");\n                else\n                    Console.WriteLine(\"Failed to set mana.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void AddGoldPrompt()\n        {\n            Console.Write(\"Enter amount of gold to add: \");\n            if (int.TryParse(Console.ReadLine(), out int amount))\n            {\n                if (_trainer.AddGold(amount))\n                    Console.WriteLine($\"Added {amount} gold.\");\n                else\n                    Console.WriteLine(\"Failed to add gold.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void SetExperienceManually()\n        {\n            Console.Write(\"Enter new experience value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                if (_trainer.SetExperience(value))\n                    Console.WriteLine($\"Experience set to {value}.\");\n                else\n                    Console.WriteLine(\"Failed to set experience.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void ShowCurrentStats()\n        {\n            Console.WriteLine();\n            Console.WriteLine(\"--- Current Stats ---\");\n            Console.WriteLine($\"Health: {_trainer.GetHealth()}\");\n            Console.WriteLine($\"Mana: {_trainer.GetMana()}\");\n            Console.WriteLine($\"Gold: {_trainer.GetGold()}\");\n            Console.WriteLine($\"Experience: {_trainer.GetExperience()}\");\n        }\n    }\n}\n"
    },
