        "path": "cronos-the-new-dawn-trainer/Program.cs",
        "content": "using System;\nusing System.Threading.Tasks;\n\nnamespace CronosNewDawnTrainer\n{\n    /// <summary>\n    /// Entry point for the Cronos: The New Dawn Trainer application.\n    /// Initializes the trainer core and launches the console UI.\n    /// </summary>\n    class Program\n    {\n        /// <summary>\n        /// Main method. Runs the trainer UI asynchronously.\n        /// </summary>\n        static async Task Main(string[] args)\n        {\n            Console.Title = \"Cronos: The New Dawn Trainer\";\n\n            // Display welcome message\n            Console.WriteLine(\"Cronos: The New Dawn Trainer\");\n            Console.WriteLine(\"Use at your own risk. Ensure the game is running.\");\n            Console.WriteLine();\n\n            // Create trainer core and UI\n            using (var trainer = new TrainerCore())\n            {\n                var ui = new TrainerUI(trainer);\n                await ui.RunAsync();\n            }\n\n            Console.WriteLine(\"Trainer closed. Press any key to exit...\");\n            Console.ReadKey();\n        }\n    }\n}\n"
    },
