        "path": "cronos-the-new-dawn-trainer/tests/TrainerCoreTests.cs",
        "content": "using System;\nusing System.Threading;\nusing System.Threading.Tasks;\nusing Xunit;\n\nnamespace CronosNewDawnTrainer.Tests\n{\n    /// <summary>\n    /// Unit tests for TrainerCore class.\n    /// Since memory operations require a running process, these tests\n    /// focus on logic and boundary conditions using mocked scenarios.\n    /// </summary>\n    public class TrainerCoreTests\n    {\n        /// <summary>\n        /// Tests that SetHealth rejects negative values.\n        /// </summary>\n        [Fact]\n        public void SetHealth_NegativeValue_ReturnsFalse()\n        {\n            // Arrange\n            var trainer = new TrainerCore();\n\n            // Act & Assert\n            // Without attaching, WriteProcessMemory will fail, but we test the logic\n            // of the method's internal clamping (though it won't write).\n            // The method returns false because not attached, but the value is clamped.\n            bool result = trainer.SetHealth(-100);\n            Assert.False(result); // Fails because not attached\n        }\n\n        /// <summary>\n        /// Tests that SetMana rejects negative values.\n        /// </summary>\n        [Fact]\n        public void SetMana_NegativeValue_ReturnsFalse()\n        {\n            var trainer = new TrainerCore();\n            bool result = trainer.SetMana(-10);\n            Assert.False(result);\n        }\n\n        /// <summary>\n        /// Tests that SetGold rejects negative values.\n        /// </summary>\n        [Fact]\n        public void SetGold_NegativeValue_ReturnsFalse()\n        {\n            var trainer = new TrainerCore();\n            bool result = trainer.SetGold(-1);\n            Assert.False(result);\n        }\n\n        /// <summary>\n        /// Tests that SetExperience rejects negative values.\n        /// </summary>\n        [Fact]\n        public void SetExperience_NegativeValue_ReturnsFalse()\n        {\n            var trainer = new TrainerCore();\n            bool result = trainer.SetExperience(-999);\n            Assert.False(result);\n        }\n\n        /// <summary>\n        /// Tests that GetHealth returns 0 when not attached to a process.\n        /// </summary>\n        [Fact]\n        public void GetHealth_NotAttached_ReturnsZero()\n        {\n            var trainer = new TrainerCore();\n            int health = trainer.GetHealth();\n            Assert.Equal(0, health);\n        }\n
